namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // per-core conservative UB share
static constexpr uint32_t ALIGN_ELEMS = 128;             // prefer 128-aligned lengths for DMA/vector
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dMinAddMultiplyCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const uint32_t n = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t cin = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t h = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t w = static_cast<uint32_t>(x_shape->GetDim(3));

    const uint32_t cout = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t kH = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t kW = static_cast<uint32_t>(w_shape->GetDim(3));
    // We assume square kernels with stride=1, dilation=1, padding=0
    const uint32_t k = kH;  // == kW

    const uint32_t ho = (h >= k) ? (h - k + 1) : 0;
    const uint32_t wo = (w >= k) ? (w - k + 1) : 0;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const bool *hasBiasPtr = attrs->GetAttrPointer<bool>(0);
    const bool hasBias = (hasBiasPtr != nullptr) ? *hasBiasPtr : false;

    // UB requirement per width tile: yBuf + xBuf + tmpBuf + wVec = 4 * tileW floats -> bytes = 16 * tileW
    uint32_t maxTile = UB_BUDGET_BYTES / 16;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileW = (wo == 0) ? ALIGN_ELEMS : maxTile;
    if (wo < tileW) {
        const uint32_t aligned = AlignDown(wo, ALIGN_ELEMS);
        tileW = (aligned > 0) ? aligned : wo;
    }

    // Task parallelism across (n, cout, ho)
    const uint32_t totalTasks = (ho == 0) ? 1u : (n * cout * ho);
    uint32_t blockDim = totalTasks;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_n(n);
    tiling.set_cin(cin);
    tiling.set_cout(cout);
    tiling.set_h(h);
    tiling.set_w(w);
    tiling.set_k(k);
    tiling.set_ho(ho);
    tiling.set_wo(wo);
    tiling.set_tileW(tileW);
    tiling.set_blockDim(blockDim);
    tiling.set_hasBiasFlag(hasBias ? 1u : 0u);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

