python_bind_src="""

#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv2d_min_add_multiply_impl_npu(const at::Tensor& x,
                                            const at::Tensor& weight,
                                            c10::optional<at::Tensor> conv_bias_opt,
                                            const at::Tensor& post_bias,
                                            const at::Tensor& constant_value,
                                            const at::Tensor& scaling_factor) {
    at::Tensor result;

    // Infer output shape: N, Cout, H-K+1, W-K+1 (stride=1, pad=0, dil=1)
    const auto N = x.size(0);
    const auto Cin = x.size(1);
    const auto H = x.size(2);
    const auto W = x.size(3);
    const auto Cout = weight.size(0);
    const auto K = weight.size(2);
    const auto Ho = H - K + 1;
    const auto Wo = W - K + 1;

    result = at::empty({N, Cout, Ho, Wo}, x.options());

    const bool has_bias = conv_bias_opt.has_value();
    at::Tensor conv_bias = has_bias ? conv_bias_opt.value() : at::Tensor();

    EXEC_NPU_CMD(aclnnConv2dMinAddMultiplyCustom,
                 x, weight, conv_bias, post_bias, constant_value, scaling_factor,
                 has_bias, result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv2d_min_add_multiply_custom", &conv2d_min_add_multiply_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("conv2d_min_add_multiply_custom", &conv2d_min_add_multiply_impl_npu,
          "Conv2D -> Min(clip) -> Add post-bias -> Multiply scaling (Conv2dMinAddMultiplyCustom on NPU)");
}
